  {{ base_url }}/work
  weekly
  0.9
  {{ now.strftime('%Y-%m-%d') }}



  {{ base_url }}/writing
  weekly
  0.8
  {{ now.strftime('%Y-%m-%d') }}



  {{ base_url }}/about
  monthly
  0.8
  {{ now.strftime('%Y-%m-%d') }}



  {{ base_url }}/contact
  monthly
  0.7
  {{ now.strftime('%Y-%m-%d') }}



  {{ base_url }}/hire
