{% for project in projects %}
  {% if project.is_visible %}

      {{ base_url }}/work/{{ project.slug }}
      monthly
      0.8
      {{ project.updated_at.strftime('%Y-%m-%d') if project.updated_at else now.strftime('%Y-%m-%d') }}

  {% endif %}
{% endfor %}
